/**
 * Unit Tests: Queue Types & Factories
 * Valida os tipos e factories de render (src/lib/queue/types.ts)
 */

import {
  createMockSlide,
  createMockRenderConfig,
  createMockRenderPayload,
} from '../../helpers/test-utils';

describe('RenderSlide factory', () => {
  it('should create a valid slide with defaults', () => {
    const slide = createMockSlide();
    expect(slide).toHaveProperty('id');
    expect(slide.content).toBe('<p>Test content</p>');
    expect(slide.duration).toBe(5);
    expect(slide.transition).toBe('fade');
  });

  it('should override fields', () => {
    const slide = createMockSlide({ title: 'Custom', duration: 10 });
    expect(slide.title).toBe('Custom');
    expect(slide.duration).toBe(10);
  });

  it('should generate unique IDs', () => {
    const a = createMockSlide();
    const b = createMockSlide();
    expect(a.id).not.toBe(b.id);
  });
});

describe('RenderConfig factory', () => {
  it('should create config with sensible defaults', () => {
    const config = createMockRenderConfig();
    expect(config.resolution).toBe('1920x1080');
    expect(config.fps).toBe(30);
    expect(config.format).toBe('mp4');
    expect(config.test).toBe(true);
  });

  it('should override format', () => {
    const config = createMockRenderConfig({ format: 'webm', fps: 60 });
    expect(config.format).toBe('webm');
    expect(config.fps).toBe(60);
  });
});

describe('RenderTaskPayload factory', () => {
  it('should create a complete payload', () => {
    const payload = createMockRenderPayload();
    expect(payload.jobId).toBeDefined();
    expect(payload.projectId).toBeDefined();
    expect(payload.userId).toBeDefined();
    expect(payload.type).toBe('render');
    expect(payload.slides).toHaveLength(1);
    expect(payload.config).toBeDefined();
  });

  it('should accept custom slides', () => {
    const slides = [
      createMockSlide({ title: 'Slide 1' }),
      createMockSlide({ title: 'Slide 2' }),
    ];
    const payload = createMockRenderPayload({ slides });
    expect(payload.slides).toHaveLength(2);
    expect(payload.slides?.[0].title).toBe('Slide 1');
    expect(payload.slides?.[1].title).toBe('Slide 2');
  });

  it('should accept custom config', () => {
    const payload = createMockRenderPayload({
      config: createMockRenderConfig({ format: 'mov', quality: 'low' }),
    });
    expect(payload.config?.format).toBe('mov');
    expect(payload.config?.quality).toBe('low');
  });
});
